  5→export type CustomerTier = 'bronze' | 'silver' | 'gold' | 'vip';
  6→export type MerchantPlan = 'free' | 'pro' | 'business';
  7→export type CampaignStatus = 'draft' | 'scheduled' | 'sent' | 'cancelled';
  8→export type NotificationType = 'campaign' | 'reward_available' | 'expiration_warning' | 'proximity' | 'welcome' | 'referral';
