 1→import { createClient } from '@/lib/supabase/server';
 2→import { redirect } from 'next/navigation';
 3→import { CampaignForm } from '@/components/campaign-form';
 4→import { Badge } from '@/components/ui/badge';
 5→import type { MerchantPlan } from '@loyalty/shared';
 6→
 7→export default async function CampaignsPage() {
 8→  const supabase = await createClient();
 9→  const {
10→    data: { user },
11→  } = await supabase.auth.getUser();
12→  if (!user) redirect('/login');
13→
14→  const { data: merchant } = await supabase
15→    .from('merchants')
16→    .select('id, plan')
17→    .eq('user_id', user.id)
18→    .single();
19→
20→  if (!merchant) redirect('/register');
21→
22→  const { data: campaigns } = await supabase
23→    .from('campaigns')
24→    .select('*')
25→    .eq('merchant_id', merchant.id)
26→    .order('created_at', { ascending: false });
27→
28→  return (
29→    <div>
30→      <h2 className="text-2xl font-bold mb-6">Campaigns</h2>
31→      <div className="grid gap-6 lg:grid-cols-2">
32→        <CampaignForm
33→          merchantId={merchant.id}
34→          merchantPlan={merchant.plan as MerchantPlan}
35→        />
36→        <div>
37→          <h3 className="font-semibold mb-3">Past Campaigns</h3>
38→          {!campaigns?.length ? (
39→            <p className="text-gray-500">No campaigns sent yet.</p>
40→          ) : (
41→            <div className="space-y-3">
42→              {campaigns.map((c) => (
43→                <div key={c.id} className="p-4 border rounded-lg">
44→                  <div className="flex justify-between items-start">
45→                    <div>
46→                      <div className="flex items-center gap-2">
47→                        <p className="font-medium">{c.title}</p>
48→                        {c.variant && (
49→                          <Badge variant="outline" className="text-xs">
50→                            Variant {c.variant}
51→                          </Badge>
52→                        )}
53→                      </div>
54→                      <p className="text-sm text-gray-500 mt-1">{c.body}</p>
55→                    </div>
56→                    <Badge
57→                      variant={c.status === 'sent' ? 'default' : 'secondary'}
58→                    >
59→                      {c.status}
60→                    </Badge>
61→                  </div>
62→                  <div className="flex items-center gap-4 mt-2">
63→                    {c.opens > 0 && (
64→                      <span className="text-xs text-gray-500">
65→                        {c.opens} opens
66→                      </span>
67→                    )}
68→                    {c.clicks > 0 && (
69→                      <span className="text-xs text-gray-500">
70→                        {c.clicks} clicks
71→                      </span>
72→                    )}
73→                    {c.sent_at && (
74→                      <p className="text-xs text-gray-400">
75→                        Sent {new Date(c.sent_at).toLocaleString()}
76→                      </p>
77→                    )}
78→                  </div>
79→                </div>
80→              ))}
81→            </div>
82→          )}
83→        </div>
84→      </div>
85→    </div>
86→  );
87→}
