  1→import { createClient } from '@/lib/supabase/server';
  2→import { redirect } from 'next/navigation';
  3→import Link from 'next/link';
  4→import { Button } from '@/components/ui/button';
  5→import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
  6→import { Badge } from '@/components/ui/badge';
  7→import { getProgramLimit, isPlanAtLimit } from '@/lib/plan-limits';
  8→import type { MerchantPlan } from '@loyalty/shared';
  9→
 10→export default async function ProgramsPage() {
 11→  const supabase = await createClient();
 12→  const {
 13→    data: { user },
 14→  } = await supabase.auth.getUser();
 15→  if (!user) redirect('/login');
 16→
 17→  const { data: merchant } = await supabase
 18→    .from('merchants')
 19→    .select('id, plan')
 20→    .eq('user_id', user.id)
 21→    .single();
 22→
 23→  if (!merchant) redirect('/register');
 24→
 25→  const { data: programs } = await supabase
 26→    .from('loyalty_programs')
 27→    .select('*')
 28→    .eq('merchant_id', merchant.id)
 29→    .order('created_at', { ascending: false });
 30→
 31→  const plan = merchant.plan as MerchantPlan;
 32→  const limit = getProgramLimit(plan);
 33→  const count = programs?.length ?? 0;
 34→  const atLimit = isPlanAtLimit(plan, count);
 35→
 36→  return (
 37→    <div>
 38→      <div className="flex justify-between items-center mb-6">
 39→        <div className="flex items-center gap-3">
 40→          <h2 className="text-2xl font-bold">Loyalty Programs</h2>
 41→          {limit !== null && (
 42→            <Badge variant="outline" className="text-xs">
 43→              {count}/{limit}
 44→            </Badge>
 45→          )}
 46→        </div>
 47→        {atLimit ? (
 48→          <Link href="/subscription">
 49→            <Button variant="outline">Upgrade to create more</Button>
 50→          </Link>
 51→        ) : (
 52→          <Link href="/programs/new">
 53→            <Button>Create Program</Button>
 54→          </Link>
 55→        )}
 56→      </div>
 57→      {!programs?.length ? (
 58→        <p className="text-gray-500">
 59→          No programs yet. Create your first loyalty program!
 60→        </p>
 61→      ) : (
 62→        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
 63→          {programs.map((p) => (
 64→            <Link key={p.id} href={`/programs/${p.id}`}>
 65→              <Card className="hover:shadow-md transition-shadow cursor-pointer">
 66→                <CardHeader>
 67→                  <div className="flex justify-between items-start">
 68→                    <CardTitle className="text-lg">{p.name}</CardTitle>
 69→                    <Badge
 70→                      variant={p.is_active ? 'default' : 'secondary'}
 71→                    >
 72→                      {p.is_active ? 'Active' : 'Inactive'}
 73→                    </Badge>
 74→                  </div>
 75→                </CardHeader>
 76→                <CardContent>
 77→                  <p className="text-sm text-gray-500 capitalize">
 78→                    {p.type} card
 79→                  </p>
 80→                  {p.type === 'stamp' && (
 81→                    <p className="text-sm">Goal: {p.stamp_goal} stamps</p>
 82→                  )}
 83→                  {p.type === 'points' && (
 84→                    <p className="text-sm">{p.points_per_euro} pts/EUR</p>
 85→                  )}
 86→                  {p.expiration_days && (
 87→                    <p className="text-sm text-gray-400">
 88→                      Expires in {p.expiration_days} days
 89→                    </p>
 90→                  )}
 91→                </CardContent>
 92→              </Card>
 93→            </Link>
 94→          ))}
 95→        </div>
 96→      )}
 97→    </div>
 98→  );
 99→}
