 1→import type { MerchantPlan } from '@loyalty/shared';
 2→
 3→const PROGRAM_LIMITS: Record<MerchantPlan, number | null> = {
 4→  free: 1,
 5→  pro: 3,
 6→  business: null,
 7→};
 8→
 9→export function getProgramLimit(plan: MerchantPlan): number | null {
10→  return PROGRAM_LIMITS[plan];
11→}
12→
13→export function isPlanAtLimit(plan: MerchantPlan, currentCount: number): boolean {
14→  const limit = PROGRAM_LIMITS[plan];
15→  return limit !== null && currentCount >= limit;
16→}
