  1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
  2→
  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers':
  6→    'authorization, x-client-info, apikey, content-type',
  7→};
  8→
  9→Deno.serve(async (req) => {
 10→  if (req.method === 'OPTIONS') {
 11→    return new Response('ok', { headers: corsHeaders });
 12→  }
 13→
 14→  try {
 15→    const supabase = createClient(
 16→      Deno.env.get('SUPABASE_URL')!,
 17→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 18→    );
 19→
 20→    const authHeader = req.headers.get('Authorization');
 21→    if (!authHeader) {
 22→      return new Response(JSON.stringify({ error: 'No auth' }), {
 23→        status: 401,
 24→        headers: corsHeaders,
 25→      });
 26→    }
 27→
 28→    const {
 29→      data: { user },
 30→      error: authError,
 31→    } = await supabase.auth.getUser(authHeader.replace('Bearer ', ''));
 32→    if (authError || !user) {
 33→      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
 34→        status: 401,
 35→        headers: corsHeaders,
 36→      });
 37→    }
 38→
 39→    const { qr_id, secret } = await req.json();
 40→
 41→    if (!qr_id || !secret) {
 42→      return new Response(
 43→        JSON.stringify({ error: 'Missing qr_id or secret' }),
 44→        { status: 400, headers: corsHeaders }
 45→      );
 46→    }
 47→
 48→    // Validate QR code
 49→    const { data: qrCode, error: qrError } = await supabase
 50→      .from('qr_codes')
 51→      .select('*, loyalty_programs(*)')
 52→      .eq('id', qr_id)
 53→      .eq('secret_key', secret)
 54→      .eq('is_active', true)
 55→      .single();
 56→
 57→    if (qrError || !qrCode) {
 58→      return new Response(JSON.stringify({ error: 'Invalid QR code' }), {
 59→        status: 400,
 60→        headers: corsHeaders,
 61→      });
 62→    }
 63→
 64→    const program = qrCode.loyalty_programs;
 65→
 66→    // Get or create customer card
 67→    let isNewCard = false;
 68→    let { data: card } = await supabase
 69→      .from('customer_cards')
 70→      .select('*')
 71→      .eq('customer_id', user.id)
 72→      .eq('program_id', program.id)
 73→      .single();
 74→
 75→    if (!card) {
 76→      isNewCard = true;
 77→
 78→      // Ensure customer record exists
 79→      const { data: existingCustomer } = await supabase
 80→        .from('customers')
 81→        .select('id')
 82→        .eq('id', user.id)
 83→        .single();
 84→
 85→      if (!existingCustomer) {
 86→        await supabase
 87→          .from('customers')
 88→          .insert({ id: user.id, email: user.email! });
 89→      }
 90→
 91→      // Ensure personal QR code exists
 92→      const { data: existingQr } = await supabase
 93→        .from('customer_qr_codes')
 94→        .select('id')
 95→        .eq('customer_id', user.id)
 96→        .single();
 97→
 98→      if (!existingQr) {
 99→        await supabase
100→          .from('customer_qr_codes')
101→          .insert({ customer_id: user.id });
102→      }
103→
104→      const { data: newCard } = await supabase
105→        .from('customer_cards')
106→        .insert({ customer_id: user.id, program_id: program.id })
107→        .select()
108→        .single();
109→
110→      card = newCard;
111→    }
112→
113→    if (!card) {
114→      return new Response(
115→        JSON.stringify({ error: 'Could not create card' }),
116→        { status: 500, headers: corsHeaders }
117→      );
118→    }
119→
120→    // Calculate value: welcome bonus for new cards, standard for existing
121→    let transactionType: string;
122→    let value: number;
123→    let welcomeBonusApplied = false;
124→
125→    if (program.type === 'stamp') {
126→      transactionType = 'stamp_add';
127→      const welcomeBonus = isNewCard ? (program.welcome_bonus_stamps ?? 0) : 0;
128→      value = 1 + welcomeBonus;
129→      welcomeBonusApplied = welcomeBonus > 0;
130→
131→      await supabase
132→        .from('customer_cards')
133→        .update({
134→          current_stamps: card.current_stamps + value,
135→          last_activity: new Date().toISOString(),
136→        })
137→        .eq('id', card.id);
138→    } else {
139→      transactionType = 'points_add';
140→      const basePoints = program.points_per_euro || 1;
141→      const welcomeBonus = isNewCard ? (program.welcome_bonus_points ?? 0) : 0;
142→      value = basePoints + welcomeBonus;
143→      welcomeBonusApplied = welcomeBonus > 0;
144→
145→      await supabase
146→        .from('customer_cards')
147→        .update({
148→          current_points: card.current_points + value,
149→          last_activity: new Date().toISOString(),
150→        })
151→        .eq('id', card.id);
152→    }
153→
154→    // Record transaction
155→    await supabase.from('transactions').insert({
156→      card_id: card.id,
157→      type: transactionType,
158→      value,
159→      validated_by: 'qr',
160→    });
161→
162→    return new Response(
163→      JSON.stringify({
164→        success: true,
165→        program_name: program.name,
166→        type: program.type,
167→        added: value,
168→        welcome_bonus: welcomeBonusApplied,
169→        is_new_card: isNewCard,
170→        new_total:
171→          program.type === 'stamp'
172→            ? card.current_stamps + value
173→            : card.current_points + value,
174→        goal: program.type === 'stamp' ? program.stamp_goal : null,
175→      }),
176→      {
177→        status: 200,
178→        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
179→      }
180→    );
181→  } catch (err) {
182→    return new Response(JSON.stringify({ error: (err as Error).message }), {
183→      status: 500,
184→      headers: corsHeaders,
185→    });
186→  }
187→});
