14→export async function POST(req: Request) {
15→  const body = await req.text();
16→  const sig = req.headers.get('stripe-signature');
17→  if (!sig)
18→    return NextResponse.json({ error: 'Missing signature' }, { status: 400 });
19→
20→  const stripe = getStripe();
21→  let event: Stripe.Event;
22→  try {
23→    event = stripe.webhooks.constructEvent(
24→      body,
25→      sig,
26→      process.env.STRIPE_WEBHOOK_SECRET!
27→    );
28→  } catch {
29→    return NextResponse.json({ error: 'Invalid signature' }, { status: 400 });
30→  }
31→
32→  const supabase = getAdminClient();
33→
34→  switch (event.type) {
35→    case 'customer.subscription.created':
36→    case 'customer.subscription.updated': {
37→      const sub = event.data.object as Stripe.Subscription;
38→      const priceId = sub.items.data[0]?.price?.id;
39→      let plan = 'free';
40→      if (priceId === process.env.STRIPE_PRO_PRICE_ID) plan = 'pro';
41→      else if (priceId === process.env.STRIPE_BUSINESS_PRICE_ID)
42→        plan = 'business';
43→
44→      await supabase
45→        .from('merchants')
46→        .update({ plan, subscription_status: sub.status })
47→        .eq('stripe_customer_id', sub.customer as string);
48→      break;
49→    }
50→    case 'customer.subscription.deleted': {
51→      const sub = event.data.object as Stripe.Subscription;
52→      await supabase
53→        .from('merchants')
54→        .update({ plan: 'free', subscription_status: 'cancelled' })
55→        .eq('stripe_customer_id', sub.customer as string);
56→      break;
57→    }
58→  }
59→
60→  return NextResponse.json({ received: true });
61→}
