  4→// n8n webhook endpoint for AI-driven marketing automation
  5→// POST /api/n8n/webhook
  6→// Headers: x-webhook-secret: <shared secret between n8n and this app>
  7→// Body depends on action:
  8→//
  9→// action: "send_campaign" → { merchant_id, title, body, target_segment, type? }
 10→// action: "send_notification" → { customer_id, title, body, type, deep_link? }
 11→// action: "get_inactive_customers" → { merchant_id, days_inactive: number }
 12→// action: "get_campaign_stats" → { merchant_id }
 13→
 14→export async function POST(request: NextRequest) {
 15→  try {
 16→    const webhookSecret = request.headers.get('x-webhook-secret');
 17→    const expectedSecret = process.env.N8N_WEBHOOK_SECRET;
 18→
 19→    if (!expectedSecret || webhookSecret !== expectedSecret) {
 20→      return NextResponse.json(
 21→        { error: 'Invalid webhook secret' },
 22→        { status: 401 }
 23→      );
 24→    }
 25→
 26→    const supabase = createClient(
 27→      process.env.NEXT_PUBLIC_SUPABASE_URL!,
 28→      process.env.SUPABASE_SERVICE_ROLE_KEY!
 29→    );
 30→
 31→    const body = await request.json();
 32→    const { action } = body;
 33→
 34→    switch (action) {
 35→      case 'send_campaign': {
 36→        const { merchant_id, title, body: campaignBody, target_segment, type } = body;
 37→
 38→        if (!merchant_id || !title || !campaignBody) {
 39→          return NextResponse.json(
 40→            { error: 'Missing merchant_id, title, or body' },
 41→            { status: 400 }
 42→          );
 43→        }
 44→
 45→        // Verify merchant exists and has AI campaigns enabled
 46→        const { data: merchant } = await supabase
 47→          .from('merchants')
 48→          .select('id, ai_campaigns_mode')
 49→          .eq('id', merchant_id)
 50→          .single();
 51→
 52→        if (!merchant) {
 53→          return NextResponse.json({ error: 'Merchant not found' }, { status: 404 });
 54→        }
 55→
 56→        if (merchant.ai_campaigns_mode === 'manual') {
 57→          return NextResponse.json(
 58→            { error: 'Merchant has AI campaigns disabled (manual mode)' },
 59→            { status: 403 }
 60→          );
 61→        }
 62→
 63→        const status = merchant.ai_campaigns_mode === 'autonomous' ? 'sent' : 'draft';
 64→
 65→        const { data: campaign, error: campErr } = await supabase
 66→          .from('campaigns')
 67→          .insert({
 68→            merchant_id,
 69→            title,
 70→            body: campaignBody,
 71→            target_segment: target_segment || 'all',
 72→            type: type || 'push',
 73→            status,
 74→            sent_at: status === 'sent' ? new Date().toISOString() : null,
 75→          })
 76→          .select()
 77→          .single();
 78→
 79→        if (campErr) {
 80→          return NextResponse.json({ error: campErr.message }, { status: 500 });
 81→        }
 82→
 83→        return NextResponse.json({
 84→          success: true,
 85→          campaign_id: campaign.id,
 86→          status,
 87→          message:
 88→            status === 'sent'
 89→              ? 'Campaign sent (autonomous mode)'
 90→              : 'Campaign created as draft (assisted mode — merchant must approve)',
 91→        });
 92→      }
 93→
 94→      case 'send_notification': {
 95→        const { customer_id, title, body: notifBody, type, deep_link } = body;
 96→
 97→        if (!customer_id || !title || !notifBody || !type) {
 98→          return NextResponse.json(
 99→            { error: 'Missing required fields' },
100→            { status: 400 }
101→          );
102→        }
103→
104→        const { error: notifErr } = await supabase
105→          .from('notifications')
106→          .insert({
107→            customer_id,
108→            title,
109→            body: notifBody,
110→            type,
111→            deep_link: deep_link || null,
112→          });
113→
114→        if (notifErr) {
115→          return NextResponse.json({ error: notifErr.message }, { status: 500 });
116→        }
117→
118→        return NextResponse.json({ success: true });
119→      }
120→
121→      case 'get_inactive_customers': {
122→        const { merchant_id, days_inactive } = body;
123→
124→        if (!merchant_id || !days_inactive) {
125→          return NextResponse.json(
126→            { error: 'Missing merchant_id or days_inactive' },
127→            { status: 400 }
128→          );
129→        }
130→
131→        const cutoffDate = new Date();
132→        cutoffDate.setDate(cutoffDate.getDate() - days_inactive);
133→
134→        const { data: inactiveCards } = await supabase
135→          .from('customer_cards')
136→          .select('customer_id, last_activity, customers(email, name)')
137→          .lt('last_activity', cutoffDate.toISOString())
138→          .in(
139→            'program_id',
140→            (
141→              await supabase
142→                .from('loyalty_programs')
143→                .select('id')
144→                .eq('merchant_id', merchant_id)
145→            ).data?.map((p: any) => p.id) ?? []
146→          );
147→
148→        return NextResponse.json({
149→          count: inactiveCards?.length ?? 0,
150→          customers: inactiveCards ?? [],
151→        });
152→      }
153→
154→      case 'get_campaign_stats': {
155→        const { merchant_id } = body;
156→
157→        if (!merchant_id) {
158→          return NextResponse.json(
159→            { error: 'Missing merchant_id' },
160→            { status: 400 }
161→          );
162→        }
163→
164→        const { data: campaigns } = await supabase
165→          .from('campaigns')
166→          .select('id, title, status, opens, clicks, conversions, sent_at')
167→          .eq('merchant_id', merchant_id)
168→          .order('created_at', { ascending: false })
169→          .limit(20);
170→
171→        return NextResponse.json({ campaigns: campaigns ?? [] });
172→      }
173→
174→      default:
175→        return NextResponse.json(
176→          { error: `Unknown action: ${action}` },
177→          { status: 400 }
178→        );
179→    }
180→  } catch {
181→    return NextResponse.json(
182→      { error: 'Internal server error' },
183→      { status: 500 }
184→    );
185→  }
186→}
