 50→      'Unlimited push notifications',
 51→      'Advanced analytics',
 52→      'Customer segments',
 53→    ],
 54→  },
 55→  {
 56→    id: 'business',
 57→    name: 'Business',
 58→    price: '79',
 59→    period: '/month',
 60→    description: 'For large-scale operations',
 61→    features: [
 62→      'Unlimited programs',
 63→      'Advanced campaigns',
 64→      'A/B testing',
 65→      'Multi-location support',
 66→      'API access',
 67→      'Priority support',
 68→    ],
 69→  },
 70→];
 71→
 72→export default function SubscriptionPage() {
 73→  const searchParams = useSearchParams();
 74→  const success = searchParams.get('success');
 75→  const cancelled = searchParams.get('cancelled');
 76→
 77→  const [currentPlan, setCurrentPlan] = useState<string>('free');
 78→  const [subscriptionStatus, setSubscriptionStatus] = useState<string>('active');
 79→  const [hasStripeCustomer, setHasStripeCustomer] = useState(false);
 80→  const [loading, setLoading] = useState<string | null>(null);
 81→  const [portalLoading, setPortalLoading] = useState(false);
 82→
 83→  useEffect(() => {
 84→    async function fetchPlan() {
 85→      const supabase = createClient();
 86→      const {
 87→        data: { user },
 88→      } = await supabase.auth.getUser();
 89→      if (!user) return;
 90→
 91→      const { data: merchant } = await supabase
 92→        .from('merchants')
 93→        .select('plan, subscription_status, stripe_customer_id')
 94→        .eq('user_id', user.id)
 95→        .single();
 96→
 97→      if (merchant) {
 98→        setCurrentPlan(merchant.plan);
 99→        setSubscriptionStatus(merchant.subscription_status);
100→        setHasStripeCustomer(!!merchant.stripe_customer_id);
101→      }
102→    }
103→    fetchPlan();
104→  }, []);
105→
106→  async function handleUpgrade(plan: string) {
107→    if (plan === 'free' || plan === currentPlan) return;
108→
109→    setLoading(plan);
110→    try {
111→      const res = await fetch('/api/stripe/checkout', {
112→        method: 'POST',
113→        headers: { 'Content-Type': 'application/json' },
114→        body: JSON.stringify({ plan }),
115→      });
116→
117→      const data = await res.json();
118→      if (data.url) {
119→        window.location.href = data.url;
120→      }
121→    } catch (err) {
122→      console.error('Checkout error:', err);
123→    } finally {
124→      setLoading(null);
125→    }
126→  }
127→
128→  async function handleManageBilling() {
129→    setPortalLoading(true);
130→    try {
131→      const res = await fetch('/api/stripe/portal', { method: 'POST' });
132→      const data = await res.json();
133→      if (data.url) {
134→        window.location.href = data.url;
135→      }
136→    } catch (err) {
137→      console.error('Portal error:', err);
138→    } finally {
139→      setPortalLoading(false);
140→    }
141→  }
142→
143→  return (
144→    <div>
145→      <div className="flex items-center justify-between mb-2">
146→        <h2 className="text-2xl font-bold">Subscription</h2>
147→        {hasStripeCustomer && currentPlan !== 'free' && (
148→          <Button
149→            variant="outline"
150→            onClick={handleManageBilling}
151→            disabled={portalLoading}
152→            className="gap-2"
153→          >
154→            <CreditCard className="h-4 w-4" />
155→            {portalLoading ? 'Loading...' : 'Manage Billing'}
156→            <ExternalLink className="h-3 w-3" />
157→          </Button>
158→        )}
159→      </div>
160→      <p className="text-gray-500 mt-2 mb-8">
161→        Choose the plan that fits your business needs.
162→      </p>
163→
164→      {success && (
165→        <div className="mb-6 rounded-lg border border-green-200 bg-green-50 p-4 text-green-800">
166→          Your subscription has been activated successfully!
167→        </div>
168→      )}
169→
170→      {cancelled && (
171→        <div className="mb-6 rounded-lg border border-yellow-200 bg-yellow-50 p-4 text-yellow-800">
172→          Checkout was cancelled. You can try again when you are ready.
173→        </div>
174→      )}
175→
176→      {currentPlan !== 'free' && subscriptionStatus === 'cancelled' && (
177→        <div className="mb-6 rounded-lg border border-red-200 bg-red-50 p-4 text-red-800">
178→          Your subscription has been cancelled. You will be downgraded to the
179→          Free plan at the end of your billing period.
180→        </div>
181→      )}
182→
183→      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
184→        {plans.map((plan) => {
185→          const isCurrent = plan.id === currentPlan;
186→          const isUpgrade =
187→            plan.id !== 'free' &&
188→            plans.findIndex((p) => p.id === plan.id) >
189→              plans.findIndex((p) => p.id === currentPlan);
190→          const isDowngrade =
191→            plans.findIndex((p) => p.id === plan.id) <
192→            plans.findIndex((p) => p.id === currentPlan);
193→
194→          return (
195→            <Card
196→              key={plan.id}
197→              className={
198→                isCurrent ? 'border-indigo-500 ring-2 ring-indigo-500' : ''
199→              }
200→            >
201→              <CardHeader>
202→                <div className="flex items-center justify-between">
203→                  <CardTitle className="text-lg">{plan.name}</CardTitle>
204→                  {isCurrent && <Badge variant="default">Current Plan</Badge>}
205→                </div>
206→                <CardDescription>{plan.description}</CardDescription>
207→              </CardHeader>
208→              <CardContent>
209→                <div className="mb-6">
210→                  <span className="text-4xl font-bold">{plan.price}&#8364;</span>
211→                  <span className="text-gray-500">{plan.period}</span>
212→                </div>
213→                <ul className="space-y-3">
214→                  {plan.features.map((feature) => (
215→                    <li key={feature} className="flex items-center gap-2">
216→                      <Check className="h-4 w-4 text-green-500 shrink-0" />
217→                      <span className="text-sm">{feature}</span>
218→                    </li>
219→                  ))}
220→                </ul>
221→              </CardContent>
222→              <CardFooter>
223→                {isCurrent ? (
224→                  <Button variant="outline" className="w-full" disabled>
225→                    Current Plan
226→                  </Button>
227→                ) : isUpgrade ? (
228→                  <Button
229→                    className="w-full"
230→                    onClick={() => handleUpgrade(plan.id)}
231→                    disabled={loading !== null}
232→                  >
233→                    {loading === plan.id ? 'Redirecting...' : 'Upgrade'}
234→                  </Button>
235→                ) : isDowngrade && hasStripeCustomer ? (
236→                  <Button
237→                    variant="outline"
238→                    className="w-full"
239→                    onClick={handleManageBilling}
240→                    disabled={portalLoading}
241→                  >
242→                    {portalLoading ? 'Loading...' : 'Downgrade via Portal'}
243→                  </Button>
244→                ) : (
245→                  <Button variant="outline" className="w-full" disabled>
246→                    {plan.id === 'free' ? 'Free tier' : 'Downgrade'}
247→                  </Button>
248→                )}
249→              </CardFooter>
250→            </Card>
251→          );
252→        })}
253→      </div>
254→
255→      {/* Plan comparison */}
256→      {currentPlan !== 'free' && hasStripeCustomer && (
257→        <div className="mt-8 p-4 bg-gray-50 rounded-lg border">
258→          <h3 className="font-semibold mb-2">Billing Management</h3>
259→          <p className="text-sm text-gray-500 mb-3">
260→            View invoices, update payment method, or cancel your subscription
261→            through the Stripe Customer Portal.
262→          </p>
263→          <Button
264→            variant="outline"
265→            size="sm"
266→            onClick={handleManageBilling}
267→            disabled={portalLoading}
268→            className="gap-2"
269→          >
270→            <ExternalLink className="h-3 w-3" />
271→            {portalLoading ? 'Loading...' : 'Open Billing Portal'}
272→          </Button>
273→        </div>
274→      )}
275→    </div>
276→  );
277→}
